package com.restaurantcraft.registry; import com.restaurantcraft.RestaurantCraft; import com.restaurantcraft.entity.*; import net.minecraft.world.entity.*; import net.minecraftforge.client.event.EntityRenderersEvent; import net.minecraftforge.eventbus.api.IEventBus; import net.minecraftforge.registries.*; public class ModEntityTypes { public static final DeferredRegister<EntityType<?>> ENTITIES=DeferredRegister.create(ForgeRegistries.ENTITY_TYPES,RestaurantCraft.MODID); public static final RegistryObject<EntityType<CustomerEntity>> CUSTOMER=ENTITIES.register("customer",()->EntityType.Builder.of(CustomerEntity::new, MobCategory.CREATURE).sized(0.6f,1.95f).build("customer")); public static void register(IEventBus bus){ENTITIES.register(bus);} public static void registerRenderers(EntityRenderersEvent.RegisterRenderers e){e.registerEntityRenderer(CUSTOMER.get(),CustomerEntityRenderer::new);} }
